title = #{title}, content = #{content}, summary = #{summary}, cover_image_url = #{coverImageUrl}, view_count = #{viewCount}, like_count = #{likeCount}, comment_count = #{commentCount}, status = #{status}, visibility = #{visibility}, is_top = #{isTop}, published_at = #{publishedAt}, updated_at = NOW()
